.char-stagger-link {
  display: inline-flex;
  text-decoration: none;
  color: inherit;
  transition: color 0.5s cubic-bezier(0.625, 0.05, 0, 1);
}

.char-stagger-link:hover {
  color: var(--char-hover-color, currentColor);
}

.char-stagger-link__inner {
  display: inline-block;
  position: relative;
}

.char-stagger-link__text {
  overflow: hidden;
  position: relative;
  display: inline-block;
  line-height: 1.2;
}

.char-stagger-link__text span {
  display: inline-block;
  position: relative;
  text-shadow: 0px 1.3em currentColor;
  transform: translateY(0em) rotate(0.001deg);
  transition: transform 0.6s cubic-bezier(0.625, 0.05, 0, 1);
  will-change: transform;
}

.char-stagger-link:hover .char-stagger-link__text span {
  transform: translateY(-1.3em) rotate(0.001deg);
}

.link-line {
  position: relative;
  width: fit-content;
}

.link-line::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 15%;
  width: 100%;
  height: 1.5px;
  background-color: currentColor;
  transform: scaleX(0);
  transform-origin: right;
  transition: transform 0.5s cubic-bezier(0.625, 0.05, 0, 1);
}

.char-stagger-link:hover .link-line::after {
  transform: scaleX(1);
  transform-origin: left;
}

.char-stagger-link__icon {
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: flex-start;
}

.icon-wrapper {
  display: flex;
  width: max-content;
  transform: translateX(-100%);
  transition: transform 0.5s cubic-bezier(0.625, 0.05, 0, 1);
  will-change: transform;
}

.char-stagger-link:hover .icon-wrapper {
  transform: translateX(5%);
}

.char-stagger-link__svg {
  flex: 0 0 auto;
  width: 100%;
  height: 100%;
}

"use client";

import React, { useEffect, useRef } from "react";
import Link from "next/link";
import { ArrowRight } from "lucide-react";
import "./char-stagger-button.css";

export function CharStaggerButton({
  text = "",
  href = "#",
  className = "",
  textClassName = "",
  linkProps = {},
  children,
  staggerStep = 0.01,
  showLine = false,
  lineClassName = "",
  hoverColor = "#ff6b00",
  showArrow = false,
  icon: Icon = ArrowRight,
  iconClassName = "",
  onClick,
  ...props
}) {
  const textRef = useRef(null);

  useEffect(() => {
    const el = textRef.current;
    if (!el) return;

    const sourceText = text || el.getAttribute("data-text") || "";
    el.innerHTML = "";

    [...sourceText].forEach((char, index) => {
      const span = document.createElement("span");
      span.textContent = char;
      span.style.transitionDelay = `${index * staggerStep}s`;

      if (char === " ") {
        span.style.whiteSpace = "pre";
      }

      el.appendChild(span);
    });
  }, [text, staggerStep]);

  return (
    <Link
      href={href}
      {...linkProps}
      {...props}
      onClick={onClick}
      className={`char-stagger-link group inline-flex items-center gap-2 ${className}`}
      style={{ "--char-hover-color": hoverColor }}
    >
      <div className="mt-[0.3vw]">
        <span
          className={`char-stagger-link__inner ${
            showLine ? `link-line ${lineClassName}` : ""
          }`}
        >
          <span
            ref={textRef}
            data-text={typeof children === "string" ? children : text}
            className={`char-stagger-link__text ${textClassName}`}
          >
            {typeof children === "string" ? children : text}
          </span>
        </span>
      </div>

      {showArrow && Icon && (
        <div className={`char-stagger-link__icon ${iconClassName}`}>
          <div className={`icon-wrapper ${iconClassName}`}>
            <Icon className="char-stagger-link__svg" />
            <Icon className="char-stagger-link__svg" />
          </div>
        </div>
      )}
    </Link>
  );
}
